var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"도시가 사라지고 함선 복도가 나타났어요.","JPN":"都市が消えて艦船の廊下が現われました。","ENG":"The city disappeared and we're in a ship corridor now.","TWN":"城市消失後，出現的是艦船的走廊？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"바루나스트라는 아디트야 님이 전대의 함선에 지어준 이름이에요.","JPN":"ヴァルナストラはアーディティヤ様が戦隊の艦船に付けた名前です。","ENG":"Varunastra is the name Miss Aditya gave to the division's ship.","TWN":"伐樓拿之艦是阿迪亞給前代艦船取的名字。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"바로 이 침식체의 원래 모습이죠.","JPN":"この侵食体の本当の姿です。","ENG":"This is what the C.O. used to look like.","TWN":"這就是這個侵蝕體原本的樣子。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"바루나스트라가 함선이었을 적의 복도네요.","JPN":"ヴァルナストラが艦船だった頃の廊下ですね。","ENG":"This is the corridor from when Varunastra used to be a ship.","TWN":"這裡是伐樓拿之艦作為艦船時的走廊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"좌표가 안정화되면서 본래 모습이었던 것들이 드러난 건 아닐까 싶어요.","JPN":"座標が安定して、本来の姿が段々現れているのではないでしょうか。","ENG":"As the coordinates stabilize, I think its original appearance is being revealed.","TWN":"可能隨著座標的穩定，原本的樣貌也跟著顯露出來。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"음…… 그걸 감안하고서라도 너무 조용한데…….","JPN":"うーん……そうだとしても静かすぎる気が……","ENG":"Mm... Even after taking that into account, it's too quiet...","TWN":"嗯……即便如此，但未免也太安靜……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그러고보니, 밖은 평화로운가요? 아디트야 님은 여전히 친절하신가요?","JPN":"そういえば、外は平和ですか？　アーディティヤ様は相変わらずお優しいですか？","ENG":"Come to think of it, what's it like out here? Is it peaceful? Is Miss Aditya still as kind as ever?","TWN":"說起來，外面的世界還和平嗎？阿迪亞依然和藹可親嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"바깥은 여전히 침식체가 득실거리고, 살기는 팍팍해요","JPN":"外は依然として侵食体がうじゃうじゃしてて、暮らしづらいです。","ENG":"It's still crawling with C.O.s out there, and life is hard.","TWN":"外面的世界依然充滿侵蝕體，生活也很艱辛。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야님은 이유도 모른 채 동결 캡슐에 갇혀 있었고요.","JPN":"アーディティヤ様は理由もわからないまま、凍結カプセルに閉じ込められていました。","ENG":"And Miss Aditya was put into cryogenic sleep in a capsule for some reason.","TWN":"我發現阿迪亞的時候，她莫名其妙地睡在冷凍膠囊裡。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아하하. 예상한 일이긴 했는데…….","JPN":"あはは。予想はしていましたけど……","ENG":"Ah hah hah. I expected that, but...","TWN":"呵呵呵，預料之中的事……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그래도…… 여기서 아버지 동료분도 만나고, 아버지의 기억도 보고 다행이네요.","JPN":"でも……ここでお父さんの仲間に出会って、お父さんの記憶も見られてよかったです。","ENG":"But still... I'm glad that I met my father's companions and saw some of his memories.","TWN":"不過……能在這裡見到爸爸的戰友，也看到爸爸的記憶，真是太好了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"하, 하하하. 다행이라고 해도 될지는 모르겠지만…….","JPN":"は、ははは。よかったって言ってもいいのかはわからないですけど……","ENG":"Ha, hahaha. Though I'm not really sure if I should be glad about it...","TWN":"哈，哈哈哈。雖然不知道這是不是值得高興的事……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"덧붙여서…… 저는 줄곧 혼자가 아니었다는 사실도 깨달았고요.","JPN":"それに……今まで、一人じゃなかったんだってこともわかりましたし。","ENG":"Also... I realized that I was never alone.","TWN":"此外……我還意識到我一直都不是一個人。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지가 주신 나침반이 늘 함께 있었다는 게…… 조금은 기뻤어요.","JPN":"お父さんがくれた羅針盤がずっと一緒だったってことが……ちょっと嬉しかったです。","ENG":"Knowing that his compass was with me this whole time... kind of made me happy.","TWN":"有爸爸給我的指南針一直陪伴著我……這讓我有點開心。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"흠흠! 그러고보니 아디트야 님과는 어떻게 만나신 거예요?","JPN":"コホン！　そういえば、アーディティヤ様とはどうやって出会ったんですか？","ENG":"Ahem! How did you meet Miss Aditya, anyway?","TWN":"嗯嗯！說起來，你是怎麼遇到阿迪亞的？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"카운터라는 존재가 드러나지 않았던 시절, 각성한 절 두려워한 부모님에게 버려졌어요.","JPN":"カウンターという存在が隠されていた頃、覚醒した私を恐れた両親に捨てられました。","ENG":"When Counters weren't revealed to the public, my parents abandoned me out of fear after my awakening.","TWN":"在那個制裁者還未公開的年代，我覺醒後，父母因為太害怕而選擇拋棄我。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그후 여기저기 떠돌아다니던 어느 날, 능력이 폭주해서 거대한 폭풍을 일으켰죠.","JPN":"それから、あちこち彷徨っていたある日、能力が暴走して巨大な嵐を起こしたんです。","ENG":"Then, while I was wandering around one day, my ability went out of control and caused a huge storm.","TWN":"後來有一天，我的能力在四處流浪時失控，引起巨大的風暴。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그 폭풍을 뚫고 절 데려온 아디트야는 저에게 이름을 지어주고 많은 걸 가르쳐줬습니다.","JPN":"その嵐をくぐり抜けて私を迎えいれたアーディティヤは、私に名前を付けて様々なことを教えてくれました。","ENG":"Aditya is the one who pulled me out of the storm, gave me my name, and taught me many things.","TWN":"是阿迪亞平息那場風暴，還替我取名字，並且教會我很多東西。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그리고 힘을 제어하는 법, 세상을 살아가는 법 같은 것들이요.","JPN":"力を制御する方法や、世界を生きる方法みたいなことも。","ENG":"She even taught me how to control my power and how to survive in this world.","TWN":"……控制力量的方法，處世之道之類的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"굉장히 힘든 훈련을 하긴 했지만, 모두 도움이 되었다고 생각해요.","JPN":"とてもきつい訓練でしたけど、全部役に立ったと思います。","ENG":"She also trained me very hard, but I think all of it helped.","TWN":"雖然訓練非常辛苦，但我覺得一切都是值得的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"굉장히 다사다난하셨네요. 카운터가 됐다고 부모에게 버려졌다니…….","JPN":"結構いろいろ苦労されたんですね。カウンターになったからって両親に捨てられるなんて……","ENG":"Sounds like you've been through a lot. And how could your parents just abandon you for becoming a Counter...?","TWN":"真是一波三折呢，成為制裁者後竟然被父母拋棄……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그땐 카운터가 흔한 존재가 아니었으니, 괴물이라고 여겼을 수도 있어요.","JPN":"あの時カウンターは稀な存在でしたから、化け物だと思ったのかもしれません。","ENG":"Counters weren't as common back then, so they might have mistaken me for a monster.","TWN":"那時候制裁者還不常見，人們大概會把他們當成怪物。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……그곳에서 제 아버지는 어떠셨나요? 모두에게 좋은 사람이었나요?","JPN":"……そこでは私のお父さん、どんな存在でしたか？　みんなにとっていい人でしたか？","ENG":"...What was my father like over there? Was he a good person to everyone?","TWN":"……我爸爸在你們戰隊裡是怎樣的人？他對大家好嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"태양의 첫 번째 불꽃. ","JPN":"太陽の最初の炎。 ","ENG":"The first flame of the sun.","TWN":"他是太陽的第一道火焰。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"전대원들은 그분을 그렇게 불렀어요.","JPN":"戦隊員たちはあの人をそう呼んでいました。","ENG":"That's what all the division members called him.","TWN":"隊員們都那樣稱呼他。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이번에 살아서 나간다면 아버지에 대한 이야기들을 많이 들려드릴게요.","JPN":"今回生きて出ることができたら、お父さんの話をたくさんしてあげましょう。","ENG":"If we make it out of here, I'll share stories of him with you.","TWN":"這次如果能活著出去，我願意告訴你很多關於你爸爸的故事。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"듣기론 라비라는 이름도 아디트야 님이 지어줬다고 들었거든요.","JPN":"ラビという名前もアーディティヤ様が付けたと聞きましたよ。","ENG":"From what I heard, Miss Aditya was the one who gave him the name Ravi.","TWN":"聽說拉維這個名字也是阿迪亞取的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님이…….","JPN":"アーディティヤ様が……","ENG":"Miss Aditya was...","TWN":"阿迪亞……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그러고 보니 나침반을 갖고 계셨죠. 어디 한번 꺼내 보시겠어요?","JPN":"そういえば、羅針盤を持っていましたよね？　少し見せてくれませんか？","ENG":"Come to think of it, you have a compass, right? Could you take it out for me?","TWN":"說起來，你有指南針吧。能拿出來看看嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"여기 오고 나선 바늘이 방향을 찾지 못하고 있어요. 고장난 걸까요?","JPN":"ここに来てから針が安定しなくなったんです。壊れたんでしょうか？","ENG":"The compass can't seem to point to a direction after I got here. Do you think it's broken?","TWN":"來到這裡後，指標就一直找不到方向，不會是壞掉了吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"음…… 아무래도 외부와 단절된 공간이라 이럴 가능성이 높겠네요.","JPN":"うーん……どうやら外部とは断絶されている空間だからこうなっている可能性が高いでしょうね。","ENG":"Mm... I think it's likely because this place is cut off from the outside world.","TWN":"嗯……畢竟是與外部隔絕的空間，這種可能性很高呢。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이 나침반은 같은 나침반에게 이끌리도록 설계된 장비에요.","JPN":"この羅針盤は同じ羅針盤の方向に導くように設計された装備です。","ENG":"This compass is designed to point to other compasses.","TWN":"這個指南針是設計用來指向同類型的指南針的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"전대원들은 전부 이 나침반을 소지하고, 고립되는 것을 방지하고 있죠.\xA0","JPN":"戦隊員はみんなこの羅針盤を持って、孤立することを防いでるんです。\xA0","ENG":"It was used to prevent being isolated by having all the division members possess one.\xA0","TWN":"所有隊員都有一個指南針，以防止走散。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"어둠 속에 갇힐지라도, 절대 혼자가 아니라는 사실을 깨우쳐주기 위한 의미라고나 할까…….","JPN":"闇の中に閉じ込められても、決して一人ではないと教えてくれる意味があるというか……","ENG":"It also served as a reminder that you were never alone even if you were trapped in darkness...","TWN":"同時也是某種慰藉，即使被困在黑暗中，也要讓我們明白絕不孤單……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"물론, 저는 진작에 잃어버려서 찾지도 못했지만…….","JPN":"もちろん、私はとっくに無くしてしまって探すこともできなかったんですけど……","ENG":"Of course, I lost mine long ago, and could never find it...","TWN":"當然，我早就弄丟了，根本找不到……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이 나침반을 맡기신 건, 아샤가 절대 혼자가 아니라는 사실을 알려주고 싶어서일 거예요.","JPN":"この羅針盤を渡したのは、アーシャが決して一人ではないということを教えてあげたかったからなんだと思います。","ENG":"I think he left you this compass to let you know that you were never alone, Asha.","TWN":"我想你爸爸把這個指南針交給你，是想告訴你，阿莎你也絕對不是一個人。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"어디선가 살아있을 아디트야 님을 찾아서, 앞으로 나아가길 바라신 거죠.","JPN":"どこかで生きているアーディティヤ様を探して、前に進むようにと。","ENG":"I guess he wanted you to find wherever Aditya was and move onward.","TWN":"他或許希望著你能找到在某處還活著的阿迪亞，並繼續前進。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"혼자가…… 아니었다고…….","JPN":"一人じゃ……なかった……","ENG":"I wasn't... alone...","TWN":"我從來不是……一個人……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"네. 그러니 밖으로 나가서 아디트야 님을 보러 갈까요?","JPN":"はい。だから外に出て、アーディティヤ様に会いに行きませんか？","ENG":"Yes. So, shall we go out and go look for Miss Aditya?","TWN":"那麼，我們繼續去找阿迪亞吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이번엔 반드시 혼자 두지 않을 거라고 다짐했거든요.","JPN":"今度は絶対一人にしないと決めたんです。","ENG":"I promised myself that I wouldn't let her be alone this time.","TWN":"我發誓這次絕不會再讓她一個人面對……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아디트야 님을 구할 수 있다면…….","JPN":"アーディティヤ様を助けることができるなら……","ENG":"If I can save Miss Aditya...","TWN":"如果能救出阿迪亞……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"저는 어떤 짓이라도 할 각오가 되어 있어요.","JPN":"私はなんでもする覚悟ができています。","ENG":"I'm ready to do anything.","TWN":"我願意做任何事。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"분명 아디트야님을 구할 수 있을 거예요.","JPN":"きっとアーディティヤ様を助けられるはずです。","ENG":"I'm sure we'll find Miss Aditya.","TWN":"嗯，我們一定能救出阿迪亞。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저도 힘닿는 곳까지 도와드릴 테니, 서로 힘내죠!","JPN":"私も精一杯協力しますから、一緒に頑張りましょう！","ENG":"I'll also help, so let's not give up!","TWN":"我也會盡力幫忙的，一起加油吧！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아하하. 힘들 때마다 힘을 북돋아 주는 건 부녀가 똑같네요.","JPN":"あはは。辛い時に元気づけてくれるのは父親譲りですね。","ENG":"Ah hah hah. Like father like daughter, I see you also try to cheer people up when they're down.","TWN":"呵呵呵，每當我感到疲憊時，總是能給我力量，你們父女倆真是一個樣。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"우리의 목표는 간단합니다.","JPN":"私たちの目標は簡単です。","ENG":"Our goal is simple.","TWN":"我們的目標很簡單。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"바루나스트라를 탈출하는 것이 첫 번째.","JPN":"一つ目。ヴァルナストラを脱出すること。","ENG":"First is escaping Varunastra.","TWN":"躲避伐樓拿之艦是第一步。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"허수 공간과 현실을 자유롭게 헤엄치는 바루나스트라를 현실에 고정하는 것이 두 번째입니다.","JPN":"二つ目。虚数空間と現実を自由に泳いでいるヴァルナストラを現実に固定すること。","ENG":"Next is anchoring Varunastra, which can swim freely between the Normalside and the imaginary space, to the Normalside.","TWN":"第二步，是將可以自由穿梭於虛數空間和現世的它，鎖定在現世之中。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"두 번째 목표를 무사히 달성하기 위해선, 좌표를 조정하는 아티팩트. 나가파샤를 되찾아야 합니다.","JPN":"二つ目の目標を無事達成するためには、座標を調整するアーティファクト、ナーガパーシャを取り戻さないといけません。","ENG":"In order to safely achieve our second goal, we'll need to retrieve the coordinate adjusting Artifact, Nagapasha.","TWN":"要順利達成第二個目標，就必須找回調整座標的人造神器——那伽羂索。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};